sys_script.script:
// Copyrights belong to Discover Technologies LLC. © 2019 Discover Technologies LLC
// Script Continued Below
(function executeRule(current, previous /*null when async*/) {

	current.suggested_short_description = current.email_subject;
	current.suggested_tasker_instructions = current.email_body;

	//HT - STRY0047195 this was created for the subtask count notification story

	var rec = new GlideRecordSecure('x_153465_discovert_discover_office_hierarchy');
	rec.setLimit(1);
	rec.query();
	var gta_list = '';
	while(rec.next()){
		gta_list = rec.getValue('u_global_authorities');
	}

	gta_list = gta_list.toString();

	var a = new GlideAggregate('x_153465_discovert_suggested_taskers');
	a.addEncodedQuery('active=true');
	a.addAggregate("COUNT");
	a.query();

	var totcount = 0;

	if(a.next()){
		totcount = a.getAggregate("COUNT");
	}

	totcount = parseInt(totcount)+ 1;
	totcount = totcount.toString();

	gs.eventQueue("x_153465_discovert.suggestedTaskCount", current, totcount, gta_list);

	//HT - STRY0047195 ends here

})(current, previous);
